const order = $input.first().json.body || $input.first().json;

// Build packing slip data
const packingSlipData = {
  order_number: order.order_number || order.id,
  date: order.date || new Date().toISOString().split('T')[0],
  customer_name: order.shipping?.name || order.customer_name,
  shipping_address: [
    order.shipping?.address_1 || order.shipping_address,
    order.shipping?.address_2,
    [order.shipping?.city, order.shipping?.state, order.shipping?.zip].filter(Boolean).join(', '),
    order.shipping?.country
  ].filter(Boolean).join('\n'),
  items: (order.items || order.line_items || []).map(item => ({
    name: item.name || item.title,
    sku: item.sku || '',
    quantity: item.quantity || 1,
    notes: item.properties?.gift_message ? 'GIFT - Do not include price' : ''
  })),
  special_instructions: order.note || order.notes || '',
  total_items: (order.items || order.line_items || []).reduce((sum, i) => sum + (i.quantity || 1), 0)
};

// Build shipping label data — UPDATE the from_name and from_address below!
const labelData = {
  from_name: 'Your Company Name',
  from_address: '123 Warehouse St\nCity, ST 12345',
  to_name: order.shipping?.name || order.customer_name,
  to_address: [
    order.shipping?.address_1 || order.shipping_address,
    order.shipping?.address_2,
    [order.shipping?.city, order.shipping?.state, order.shipping?.zip].filter(Boolean).join(', '),
    order.shipping?.country
  ].filter(Boolean).join('\n'),
  order_number: order.order_number || order.id,
  weight: order.total_weight || '1.0 kg',
  shipping_method: order.shipping_method || 'Standard'
};

return [{
  json: {
    packingSlipData,
    labelData,
    order_number: packingSlipData.order_number
  }
}];

const packingSlip = $('TemplateFox - Packing Slip').first().json;
const shippingLabel = $('TemplateFox - Shipping Label').first().json;
const orderNumber = $('Format Order Data').first().json.order_number;

return [{
  json: {
    order_number: orderNumber,
    packing_slip_url: packingSlip.url,
    packing_slip_filename: packingSlip.filename,
    shipping_label_url: shippingLabel.url,
    shipping_label_filename: shippingLabel.filename,
    status: 'ready'
  }
}];
